import { playSound } from "../synth.js";
import { spawnDamageNumber } from '../combat_feedback.js';

const bulletHit = (bullet, enemies, bulletRadius, player, effects) => {
  const enemiesSnapshot = [...enemies];

  for (const enemy of enemiesSnapshot) {
    if (bullet.destroyed) break;
    const indexEnemy = enemies.indexOf(enemy);
    if (indexEnemy === -1) continue;

    const distanceX = enemy.enemy.position.x - bullet.position.x;
    const distanceY = enemy.enemy.position.y - bullet.position.y;
    const distance = Math.sqrt(distanceX * distanceX + distanceY * distanceY);

    if (distance < bulletRadius + enemy.enemyRadius) {
      player.runStats?.recordShotHit?.();

      // Calculate knockback direction from bullet to enemy
      const controlEffects = bullet.controlEffects ? { ...bullet.controlEffects } : null;
      if (controlEffects && controlEffects.knockbackBonus > 0) {
        const knockLen = Math.hypot(distanceX, distanceY) || 1;
        controlEffects.knockbackDirection = {
          x: distanceX / knockLen,
          y: distanceY / knockLen,
        };
      }

      // Apply control effects to the hit enemy
      const durationMultiplier = bullet.controlDurationMultiplier || 1;
      if (enemy.applyControlEffects) {
        enemy.applyControlEffects(controlEffects, durationMultiplier);
      }

      // Chain pulse: apply control effects to nearby enemies
      const chainRadius = bullet.chainPulseRadius || 0;
      if (chainRadius > 0 && controlEffects) {
        for (const nearbyEnemy of enemiesSnapshot) {
          if (nearbyEnemy === enemy) continue;
          if (nearbyEnemy.enemy.destroyed) continue;
          const nDx = nearbyEnemy.enemy.position.x - enemy.enemy.position.x;
          const nDy = nearbyEnemy.enemy.position.y - enemy.enemy.position.y;
          const nearbyDist = Math.sqrt(nDx * nDx + nDy * nDy);
          if (nearbyDist <= chainRadius) {
            const chainControl = { ...controlEffects };
            // No knockback for chain targets, just slow/weaken
            delete chainControl.knockbackBonus;
            delete chainControl.knockbackDirection;
            if (nearbyEnemy.applyControlEffects) {
              nearbyEnemy.applyControlEffects(chainControl, durationMultiplier);
            }
            if (effects) {
              effects.pulse(nearbyEnemy.enemy, 0x5cc8ff, 6);
            }
          }
        }
      }

      const appliedDamage = enemy.kill(enemies, indexEnemy, player, effects, bullet.damage || 1);
      if (bullet.source === 'drone' && !enemies.includes(enemy) && player.skillEffects?.droneKillCreditBonus > 0) {
        player.runStats?.recordDroneKill?.();
      }
      spawnDamageNumber(
        bullet.position.x,
        bullet.position.y,
        appliedDamage || bullet.damage || 1,
        !!bullet.isCrit
      );

      if (effects) {
        const pulseColor = bullet.isCrit ? 0xff4d4d : 0xffffff;
        const explosionColor = bullet.isCrit ? 0xff2d55 : 0xffa940;
        const shakeAmount = bullet.isCrit ? 4.0 : 2.4;
        effects.pulse(enemy.enemy, pulseColor, 6);
        effects.explosion(bullet.position.x, bullet.position.y, explosionColor, bullet.isCrit ? 16 : 10);
        effects.shake(shakeAmount);
      }

      // Chain lightning proc
      const upgEffects = player.runUpgradeEffects;
      if (upgEffects && upgEffects.chainLightningChance > 0 && Math.random() < upgEffects.chainLightningChance) {
        const chainTargets = [];
        const screen = effects?.app?.screen;
        const enemiesForChain = [...enemiesSnapshot].filter(e => {
          if (e === enemy || e.enemy?.destroyed) return false;
          if (screen) {
            const { x, y } = e.enemy.position;
            if (x < 0 || x > screen.width || y < 0 || y > screen.height) return false;
          }
          return true;
        });
        enemiesForChain.sort((a, b) => {
          const da = Math.hypot(a.enemy.position.x - enemy.enemy.position.x, a.enemy.position.y - enemy.enemy.position.y);
          const db = Math.hypot(b.enemy.position.x - enemy.enemy.position.x, b.enemy.position.y - enemy.enemy.position.y);
          return da - db;
        });
        for (const nearby of enemiesForChain) {
          if (chainTargets.length >= upgEffects.chainLightningTargets) break;
          const nearbyIdx = enemies.indexOf(nearby);
          if (nearbyIdx !== -1) {
            nearby.kill(enemies, nearbyIdx, player, effects, upgEffects.chainLightningDamage);
            chainTargets.push({ x: nearby.enemy.position.x, y: nearby.enemy.position.y });
          }
        }
        if (chainTargets.length > 0 && effects?.chainLightning) {
          effects.chainLightning(enemy.enemy.position.x, enemy.enemy.position.y, chainTargets);
          playSound('lightning');
        }
      }

      if (bullet.pierceCount > 0) {
        bullet.pierceCount--;
      } else {
        bullet.visible = false;
        bullet.destroy();
      }
    }
  }
};

export default bulletHit;
